using UnityEngine;

/// <summary>
/// Habilidade de rastejar (CRW do GDD): passiva, sem botão. Enquanto activa
/// para a forma actual (form.canCrawl), detecta automaticamente quando o
/// tamanho normal do collider não cabe no espaço (tecto baixo/fenda) e troca
/// para o CapsuleCollider2D "de rastejar" (crawlColliderSize/Offset),
/// reduzindo também a velocidade horizontal máxima. Quando o espaço normal
/// volta a caber, restaura o collider normal.
///
/// [DefaultExecutionOrder(100)] garante que o FixedUpdate desta habilidade
/// corre DEPOIS do FixedUpdate do PlayerMotor2D (ordem padrão = 0), para que
/// o clamp de velocidade de rastejar seja aplicado depois do movimento
/// horizontal normal do motor.
/// </summary>
[DefaultExecutionOrder(100)]
[RequireComponent(typeof(PlayerMotor2D))]
public class CrawlAbility : MonoBehaviour, IFormAbility
{
    [Header("Detecção (CRW)")]
    [Tooltip("Layers sólidas (chão/paredes/tectos) usadas para verificar se o tamanho normal do collider cabe no espaço actual.")]
    [SerializeField] private LayerMask solidLayer;

    private PlayerMotor2D motor;

    private bool enabledForForm;

    private Vector2 normalColliderSize;
    private Vector2 normalColliderOffset;
    private Vector2 crawlColliderSize;
    private Vector2 crawlColliderOffset;

    private float crawlMaxSpeed;

    private bool isCrawling;

    /// <summary>true enquanto o player está com o collider "de rastejar" activo.</summary>
    public bool IsCrawling => isCrawling;

    private void Awake()
    {
        motor = GetComponent<PlayerMotor2D>();
    }

    public void ConfigureFromForm(AnimalFormData form)
    {
        enabledForForm = form != null && form.canCrawl;

        if (form != null)
        {
            normalColliderSize = form.colliderSize;
            normalColliderOffset = form.colliderOffset;
            crawlColliderSize = form.crawlColliderSize;
            crawlColliderOffset = form.crawlColliderOffset;
            crawlMaxSpeed = form.maxSpeed * form.crawlSpeedMultiplier;
        }

        // FormSwitcher já chamou motor.ApplyForm(form) antes disto, o que
        // repõe o collider para o tamanho normal da nova forma. Por isso
        // aqui só limpamos o nosso estado interno, sem voltar a tocar no
        // collider.
        isCrawling = false;
    }

    private void FixedUpdate()
    {
        if (!enabledForForm) return;

        if (!isCrawling)
        {
            // Tecto baixo/fenda à frente -> entra em modo rastejar.
            if (!FitsAt(normalColliderSize, normalColliderOffset))
                EnterCrawl();
        }
        else
        {
            // Já há espaço para o tamanho normal -> volta ao normal.
            if (FitsAt(normalColliderSize, normalColliderOffset))
                ExitCrawl();
        }

        if (isCrawling)
            ClampCrawlSpeed();
    }

    private void EnterCrawl()
    {
        isCrawling = true;

        motor.Capsule.size = crawlColliderSize;
        motor.Capsule.offset = crawlColliderOffset;
        motor.RecalculateGroundCheck();
    }

    private void ExitCrawl()
    {
        isCrawling = false;

        motor.Capsule.size = normalColliderSize;
        motor.Capsule.offset = normalColliderOffset;
        motor.RecalculateGroundCheck();
    }

    private void ClampCrawlSpeed()
    {
        var rb = motor.RB;
        float vx = rb.velocity.x;

        if (Mathf.Abs(vx) > crawlMaxSpeed)
            rb.velocity = new Vector2(Mathf.Sign(vx) * crawlMaxSpeed, rb.velocity.y);
    }

    /// <summary>
    /// Verifica se um CapsuleCollider2D com o tamanho/offset indicados, na
    /// posição actual do player, cabe sem sobrepor "solidLayer".
    /// </summary>
    private bool FitsAt(Vector2 size, Vector2 offset)
    {
        bool wasEnabled = motor.Capsule.enabled;
        motor.Capsule.enabled = false;

        try
        {
            Vector2 worldPos = (Vector2)transform.position + offset;

            Collider2D hit = Physics2D.OverlapCapsule(
                worldPos,
                size,
                CapsuleDirection2D.Vertical,
                0f,
                solidLayer
            );

            return hit == null;
        }
        finally
        {
            motor.Capsule.enabled = wasEnabled;
        }
    }
}
